#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#define MAXN 300000
#define MAXM 300000
#define INF INT_MAX

int n, m, s, t;
int adj[MAXN][MAXN];
int dist[MAXN];

void bfs(int start) {
    for (int i = 0; i < n; i++) {
        dist[i] = INF;
    }
    dist[start] = 0;
    int queue[MAXN];
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (adj[u][v] == 1 && dist[v] == INF) {
                dist[v] = dist[u] + 1;
                queue[rear++] = v;
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d %d", &n, &m, &s, &t);
        s--; t--;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            adj[u][v] = adj[v][u] = 1;
        }
        bfs(s);
        printf("%d\n", dist[t] == INF ? -1 : dist[t]);
    }
    return 0;
}

