#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;

const int MAXN = 300000;
const int MAXM = 300000;
const int INF = numeric_limits<int>::max();

int n, m, s, t;
vector<vector<int>> adj;
vector<int> dist;

void bfs(int start) {
    dist.assign(n, INF);
    dist[start] = 0;
    queue<int> q;
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v = 0; v < n; v++) {
            if (adj[u][v] == 1 && dist[v] == INF) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
        }
    }
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        cin >> n >> m >> s >> t;
        s--; t--;
        adj.assign(n, vector<int>(n, 0));
        for (int i = 0; i < m; i++) {
            int u, v;
            cin >> u >> v;
            u--; v--;
            adj[u][v] = adj[v][u] = 1;
        }
        bfs(s);
        cout << (dist[t] == INF ? -1 : dist[t]) << endl;
    }
    return 0;
